import{_ as i,o as e,c as l,a9 as r}from"./chunks/framework.STMWz9Nm.js";const R=JSON.parse('{"title":"Redis学习","description":"","frontmatter":{},"headers":[],"relativePath":"语言/java/08-Redis学习/08-Redis学习.md","filePath":"语言/java/08-Redis学习/08-Redis学习.md","lastUpdated":1776150380000}'),d={name:"语言/java/08-Redis学习/08-Redis学习.md"};function s(t,a,h,n,o,_){return e(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="redis学习" tabindex="-1">Redis学习 <a class="header-anchor" href="#redis学习" aria-label="Permalink to “Redis学习”">​</a></h1><p>Redis 是 Java 后端体系里最常见的缓存与高性能数据结构服务。<br> 学习 Redis 不能只停留在会 <code>set/get</code>，更重要的是理解数据结构、缓存设计、持久化、高可用和性能治理。</p><h2 id="专题目录" tabindex="-1">专题目录 <a class="header-anchor" href="#专题目录" aria-label="Permalink to “专题目录”">​</a></h2><ul><li><a href="./01-Redis核心数据结构.html">01-Redis核心数据结构</a></li><li><a href="./02-缓存设计与一致性.html">02-缓存设计与一致性</a></li><li><a href="./03-持久化与高可用.html">03-持久化与高可用</a></li><li><a href="./04-分布式锁与限流.html">04-分布式锁与限流</a></li><li><a href="./05-Redis性能优化.html">05-Redis性能优化</a></li></ul><h2 id="_1-学习定位" tabindex="-1">1. 学习定位 <a class="header-anchor" href="#_1-学习定位" aria-label="Permalink to “1. 学习定位”">​</a></h2><p>这一组内容聚焦 Redis 在 Java 后端中的实际使用。<br> 目标是让你不仅能用 Redis，还能设计出更稳的缓存和分布式协作方案。</p><h2 id="_2-学习重点" tabindex="-1">2. 学习重点 <a class="header-anchor" href="#_2-学习重点" aria-label="Permalink to “2. 学习重点”">​</a></h2><ul><li>理解 Redis 各类数据结构的适用场景</li><li>理解缓存一致性与热点问题</li><li>理解持久化和高可用如何影响线上可靠性</li><li>理解分布式锁的边界和风险</li><li>理解性能优化不只看命令，也看模型</li></ul><h2 id="_3-建议顺序" tabindex="-1">3. 建议顺序 <a class="header-anchor" href="#_3-建议顺序" aria-label="Permalink to “3. 建议顺序”">​</a></h2><ol><li>Redis核心数据结构</li><li>缓存设计与一致性</li><li>持久化与高可用</li><li>分布式锁与限流</li><li>Redis性能优化</li></ol><h2 id="_4-阶段产出" tabindex="-1">4. 阶段产出 <a class="header-anchor" href="#_4-阶段产出" aria-label="Permalink to “4. 阶段产出”">​</a></h2><ul><li>一份缓存设计总结</li><li>一份 Redis 高可用认知笔记</li><li>一份典型性能问题排查清单</li><li>一份分布式锁边界条件清单</li></ul><h2 id="_5-自测标准" tabindex="-1">5. 自测标准 <a class="header-anchor" href="#_5-自测标准" aria-label="Permalink to “5. 自测标准”">​</a></h2><ul><li>能为一个业务场景选出合适的数据结构</li><li>能说明缓存一致性和热点问题怎么处理</li><li>能解释 Redis 高可用和持久化的基本取舍</li><li>能说清 Redis 锁为什么必须校验锁归属</li></ul>',14)])])}const m=i(d,[["render",s]]);export{R as __pageData,m as default};
